  if (debug) {
    console.info('Placing order:', {
      url,
      symbol: payload.symbol,
      side: payload.side,
      type: payload.type,
      amount: payload.amount,
      price: payload.price,
      clientOrderId: payload.clientOrderId,
      timeInForce: payload.timeInForce,
      idempotencyKey,
